const input = $input.first()?.json ?? {};
const get = (key, fallback = '') => String(input[key] ?? fallback).trim();
const errors = [];

const config = {
  user_name: get('user_name'),
  city_name: get('city_name'),
  weather_latitude: get('weather_latitude'),
  weather_longitude: get('weather_longitude'),
  user_profile: get('user_profile'),
  output_language: get('output_language', 'English'),
  tech_rss_url: get('tech_rss_url'),
  jobs_rss_url: get('jobs_rss_url'),
  ntfy_topic: get('ntfy_topic'),
  ntfy_title: get('ntfy_title', 'AI Morning OS'),
  ntfy_priority: get('ntfy_priority', 'default').toLowerCase(),
  ntfy_tags: get('ntfy_tags', 'sunrise,briefing,ai'),
  groq_api_key: get('groq_api_key'),
  groq_model: get('groq_model', 'llama-3.3-70b-versatile'),
  ai_temperature: Number(get('ai_temperature', '0.6')),
  max_words: Number.parseInt(get('max_words', '220'), 10),
  max_completion_tokens: Number.parseInt(get('max_completion_tokens', '700'), 10),
};

const required = [
  'user_name',
  'city_name',
  'weather_latitude',
  'weather_longitude',
  'user_profile',
  'output_language',
  'tech_rss_url',
  'jobs_rss_url',
  'ntfy_topic',
  'groq_api_key',
  'groq_model',
];

for (const key of required) {
  if (!config[key]) errors.push(`${key} is required.`);
}

const latitude = Number(config.weather_latitude);
const longitude = Number(config.weather_longitude);
if (!Number.isFinite(latitude) || latitude < -90 || latitude > 90) {
  errors.push('weather_latitude must be a number between -90 and 90.');
}
if (!Number.isFinite(longitude) || longitude < -180 || longitude > 180) {
  errors.push('weather_longitude must be a number between -180 and 180.');
}

for (const key of ['tech_rss_url', 'jobs_rss_url']) {
  if (config[key] && !/^https?:\/\//i.test(config[key])) {
    errors.push(`${key} must start with http:// or https://.`);
  }
}

if (/CHANGE_ME|PASTE|YOUR_|TOPIC|API_KEY/i.test(config.ntfy_topic)) {
  errors.push('ntfy_topic still contains a placeholder value.');
}
if (!/^[A-Za-z0-9][A-Za-z0-9_-]{5,63}$/.test(config.ntfy_topic || '')) {
  errors.push('ntfy_topic must be 6-64 characters and use only letters, numbers, underscores, or hyphens.');
}
if (/PASTE|YOUR_|CHANGE_ME|GROQ_API_KEY/i.test(config.groq_api_key)) {
  errors.push('groq_api_key still contains a placeholder value.');
}
if (config.groq_api_key && !/^gsk_[A-Za-z0-9_-]{10,}$/.test(config.groq_api_key)) {
  errors.push('groq_api_key should look like a Groq API key starting with gsk_.');
}

if (!Number.isFinite(config.ai_temperature) || config.ai_temperature < 0 || config.ai_temperature > 2) {
  errors.push('ai_temperature must be a number between 0 and 2.');
}
if (!Number.isFinite(config.max_words) || config.max_words < 80 || config.max_words > 600) {
  errors.push('max_words must be a number between 80 and 600.');
}
if (!Number.isFinite(config.max_completion_tokens) || config.max_completion_tokens < 200 || config.max_completion_tokens > 4096) {
  errors.push('max_completion_tokens must be a number between 200 and 4096.');
}

const validPriorities = new Set(['min', 'low', 'default', 'high', 'urgent', '1', '2', '3', '4', '5']);
if (!validPriorities.has(config.ntfy_priority)) {
  errors.push('ntfy_priority must be min, low, default, high, urgent, or a value from 1 to 5.');
}

if (errors.length) {
  throw new Error(`AI Morning OS configuration error:\n- ${errors.join('\n- ')}`);
}

return [{
  json: {
    ...config,
    weather_latitude: latitude,
    weather_longitude: longitude,
    ai_temperature: config.ai_temperature,
    max_words: config.max_words,
    max_completion_tokens: config.max_completion_tokens,
    config_status: 'valid',
  },
}];

const current = $json.current ?? {};
const code = Number(current.weather_code);

const weatherLabels = new Map([
  [0, 'Clear sky'],
  [1, 'Mainly clear'],
  [2, 'Partly cloudy'],
  [3, 'Overcast'],
  [45, 'Fog'],
  [48, 'Depositing rime fog'],
  [51, 'Light drizzle'],
  [53, 'Moderate drizzle'],
  [55, 'Dense drizzle'],
  [56, 'Light freezing drizzle'],
  [57, 'Dense freezing drizzle'],
  [61, 'Slight rain'],
  [63, 'Moderate rain'],
  [65, 'Heavy rain'],
  [66, 'Light freezing rain'],
  [67, 'Heavy freezing rain'],
  [71, 'Slight snow'],
  [73, 'Moderate snow'],
  [75, 'Heavy snow'],
  [77, 'Snow grains'],
  [80, 'Slight rain showers'],
  [81, 'Moderate rain showers'],
  [82, 'Violent rain showers'],
  [85, 'Slight snow showers'],
  [86, 'Heavy snow showers'],
  [95, 'Thunderstorm'],
  [96, 'Thunderstorm with slight hail'],
  [99, 'Thunderstorm with heavy hail'],
]);

const asNumber = (value) => {
  const number = Number(value);
  return Number.isFinite(number) ? number : null;
};

const temperature = asNumber(current.temperature_2m);
const apparent = asNumber(current.apparent_temperature);
const humidity = asNumber(current.relative_humidity_2m);
const precipitation = asNumber(current.precipitation);
const wind = asNumber(current.wind_speed_10m);
const condition = weatherLabels.get(code) ?? 'Weather data unavailable';
const weatherAvailable = !$json.error && temperature !== null;

const details = [];
if (temperature !== null) details.push(`${temperature} C`);
if (apparent !== null) details.push(`feels like ${apparent} C`);
if (humidity !== null) details.push(`${humidity}% humidity`);
if (precipitation !== null) details.push(`${precipitation} mm precipitation`);
if (wind !== null) details.push(`${wind} km/h wind`);

return [{
  json: {
    weather_available: weatherAvailable,
    weather_code: Number.isFinite(code) ? code : null,
    weather_condition: condition,
    temperature_c: temperature,
    apparent_temperature_c: apparent,
    humidity_percent: humidity,
    precipitation_mm: precipitation,
    wind_speed_kmh: wind,
    weather_summary: weatherAvailable ? `${condition}; ${details.join('; ')}` : 'Weather data unavailable from Open-Meteo for this run.',
  },
}];

const config = $items('Validate Config')[0]?.json ?? {};
const weather = $items('Normalize Weather')[0]?.json ?? {};

const clean = (value) => String(value ?? '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
const truncate = (value, limit = 420) => {
  const text = clean(value);
  return text.length > limit ? `${text.slice(0, limit - 1)}...` : text;
};

const firstUsableItem = (nodeName) => {
  const items = $items(nodeName) ?? [];
  return items.find((item) => {
    const json = item?.json ?? {};
    return !json.error && (json.title || json.link || json.guid || json.description || json.contentSnippet);
  })?.json ?? {};
};

const normalizeRssItem = (item, fallbackTitle) => {
  const title = clean(item.title) || fallbackTitle;
  const link = clean(item.link) || clean(item.guid) || 'No link available';
  const published = clean(item.isoDate) || clean(item.pubDate) || clean(item.date) || 'No publish date provided';
  const summary = truncate(item.contentSnippet || item.description || item.content || item['content:encoded'] || 'No summary available');
  return { title, link, published, summary };
};

const tech = normalizeRssItem(firstUsableItem('Pick Top Tech Item'), 'Technology feed unavailable for this run');
const job = normalizeRssItem(firstUsableItem('Pick Top Job Item'), 'Career feed unavailable for this run');

const prompt = `Create a premium morning briefing for ${config.user_name}.

Audience profile:
${config.user_profile}

Location and weather:
- City: ${config.city_name}
- Current weather: ${weather.weather_summary || 'Weather data unavailable for this run.'}

Technology item:
- Title: ${tech.title}
- Link: ${tech.link}
- Published: ${tech.published}
- Summary: ${tech.summary}

Career opportunity:
- Title: ${job.title}
- Link: ${job.link}
- Published: ${job.published}
- Summary: ${job.summary}

Required output language:
${config.output_language}

Required format:
Morning Greeting
Weather Insight
Technology Analysis
Career Analysis
Match Score: X/10
Daily Strategy
Closing

Quality rules:
- Stay under ${config.max_words} words.
- Keep every URL unchanged and on its own line.
- Do not invent facts beyond the supplied weather and RSS data.
- If a feed is unavailable, say so briefly and continue with useful guidance.
- Make the career score specific to the audience profile.
- Avoid generic motivational cliches.
- Use polished, direct, executive wording.
- Return only the final notification text.`;

return [{
  json: {
    prompt,
    groq_model: config.groq_model,
    ai_temperature: config.ai_temperature,
    max_completion_tokens: config.max_completion_tokens,
    ntfy_title: config.ntfy_title,
    ntfy_priority: config.ntfy_priority,
    ntfy_tags: config.ntfy_tags,
    briefing_context: {
      city: config.city_name,
      weather: weather.weather_summary,
      technology_title: tech.title,
      technology_link: tech.link,
      career_title: job.title,
      career_link: job.link,
    },
  },
}];

const response = $input.first()?.json ?? {};
const promptItem = $items('Build AI Prompt')[0]?.json ?? {};

let body = response.choices?.[0]?.message?.content;
const errorMessage = response.error?.message || response.message || response.error || response.statusText;

if (!body || typeof body !== 'string') {
  body = [
    'AI Morning OS could not generate the briefing for this run.',
    '',
    `Reason: ${errorMessage || 'Groq returned an unexpected response.'}`,
    '',
    'Next step: check the Groq API key, model name, account limits, and the Generate Briefing (Groq) node output.',
  ].join('\n');
}

return [{
  json: {
    notification_body: body.trim(),
    ntfy_title: promptItem.ntfy_title || 'AI Morning OS',
    ntfy_priority: promptItem.ntfy_priority || 'default',
    ntfy_tags: promptItem.ntfy_tags || 'sunrise,briefing,ai',
  },
}];
